                        // Because storing events in local will cause more memory usage.
                        // The worst case would be closing the fast watcher.
                        select {
                        case wc.resultChan <- *res:
                        case <-wc.ctx.Done():
                                return
                        }
                case <-wc.ctx.Done():
                        return
                }
        }
}

