func isCancelError(err error) bool {
        if err == nil {
                return false
        }
        if err == context.Canceled {
                return true
        }
        if etcdErr, ok := err.(etcdError); ok && etcdErr.Code() == grpccodes.Canceled {
                return true
        }
        if grpcErr, ok := err.(grpcError); ok && grpcErr.GRPCStatus().Code() == grpccodes.Canceled {
                return true
        }
        return false
}

